#include <iostream>
using namespace std;

int main() {
    int x, y;
    cin >> x >> y;

    if (x > 0 && y > 0) {
        cout << "I\n";
    } else if (x < 0 && y > 0) {
        cout << "II\n";
    } else if (x < 0 && y < 0) {
        cout << "III\n";
    } else {
        cout << "IV\n";
    }

    return 0;
}
